 // Add the MCP services: the transport to use (stdio) and the tools/prompts to register.
 builder.Services
     .AddMcpServer()
     .WithStdioServerTransport()
     .WithToolsFromAssembly()
     .WithPromptsFromAssembly();

 await builder.Build().RunAsync();
